for i in range(5):
    print(i)
for i in range(2, 20, 5):
    print(i)
for i in range(10, 0, -3):
    print(i)
print(len(range(100)))
r = range(3, 9)
print(r)
print(6 in r)
for c in "abc":
    print(c)
for i in range(10):
    if i == 4:
        break
    print(i)
else:
    print("never")
for x in [10, 20, 30]:
    print(x)
else:
    print("all seen")
